mapper.select:
SELECT * FROM watering_log
WHERE plant_no = #{plantNo}
ORDER BY water_date DESC

SELECT w.*, p.nickname FROM watering_log w
JOIN my_plant p ON w.plant_no = p.plant_no
WHERE YEAR(w.water_date) = #{year}
  AND MONTH(w.water_date) = #{month}
  AND p.user_id = #{userId}
  AND p.del_yn = 'N'
ORDER BY w.water_date
